/**
 * Make request to Telegram API
 */
function makeTelegramRequest(method, postData) {
  return new Promise((resolve, reject) => {
    console.log(`[DEBUG] Making Telegram API request: ${method}`);
    console.log(`[DEBUG] Request body: ${postData.substring(0, 200)}...`);

    const options = {
      hostname: 'api.telegram.org',
      port: 443,
      path: `/bot${WEATHER_BOT_TOKEN}${method}`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData)
      }
    };

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        console.log(`[DEBUG] Telegram API response status: ${res.statusCode}`);
        console.log(`[DEBUG] Telegram API response: ${data.substring(0, 500)}...`);

        if (res.statusCode >= 200 && res.statusCode < 300) {
          const response = JSON.parse(data);
          if (response.ok) {
            console.log(`[DEBUG] Telegram API request successful`);
            resolve(response);
          } else {
            console.error(`[DEBUG] Telegram API error: ${response.description}`);
            reject(new Error(`Telegram API error: ${response.description}`));
          }
        } else {
          console.error(`[DEBUG] HTTP error ${res.statusCode}: ${data}`);
          reject(new Error(`HTTP ${res.statusCode}: ${data}`));
        }
      });
    });

    req.on('error', (error) => {
      console.error(`[DEBUG] Request error: ${error.message}`);
      reject(error);
    });

    req.write(postData);
    req.end();
  });
}

